<template><view class="page"><view class="card"><input v-model="form.name" placeholder="收货人"/><input v-model="form.phone" placeholder="手机号"/><picker mode="region" @change="regionChange"><view class="pick">{{regionText||'请选择省市区'}}</view></picker><textarea v-model="form.detail" placeholder="详细地址"/><label><checkbox :checked="form.isDefault" @click="form.isDefault=!form.isDefault"/>设为默认地址</label><button class="primary" @click="save">保存</button></view></view></template><script setup lang="ts">import { computed,ref } from 'vue';import { onLoad } from '@dcloudio/uni-app';import { addressApi } from '@/services/address';const id=ref(''),form=ref<any>({name:'',phone:'',province:'',city:'',district:'',detail:'',isDefault:false});const regionText=computed(()=>[form.value.province,form.value.city,form.value.district].filter(Boolean).join(' '));function regionChange(e:any){const v=e.detail.value;form.value.province=v[0];form.value.city=v[1];form.value.district=v[2]}async function save(){if(!form.value.name||!form.value.phone||!form.value.province||!form.value.detail){uni.showToast({title:'请填写完整地址字段',icon:'none'});return}if(id.value)await addressApi.update(id.value,form.value);else await addressApi.create(form.value);uni.showToast({title:'保存成功',icon:'success'});setTimeout(()=>uni.navigateBack(),300)}onLoad(async(o:any)=>{id.value=o.id||'';if(id.value)form.value=(await addressApi.detail(id.value)).data||form.value})</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}input,.pick,textarea{background:#f8f4ed;border-radius:12rpx;padding:20rpx;margin-top:20rpx}textarea{width:auto;height:160rpx}label{display:block;margin-top:20rpx}button{margin-top:28rpx;height:84rpx;line-height:84rpx;width:100%;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
